1	// pixel-art-scaler.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { scalePixelArt } from "./pixel-art-scaler.js";
4	
5	describe("Pixel Art Scaler", () => {
6	  it("should return empty image for empty input regardless of scale", () => {
7	    expect(scalePixelArt([], 3)).toEqual([]);
8	  });
9	  it("should return unchanged copy when scale is 1", () => {
10	    expect(scalePixelArt([["a"]], 1)).toEqual([["a"]]);
11	  });
12	  it("should replicate single pixel horizontally by scale factor", () => {
13	    expect(scalePixelArt([["a"]], 3)).toEqual([
14	      ["a", "a", "a"],
15	      ["a", "a", "a"],
16	      ["a", "a", "a"],
17	    ]);
18	  });
19	  it("should replicate single row vertically by scale factor", () => {
20	    expect(scalePixelArt([["a"]], 2)).toEqual([["a", "a"], ["a", "a"]]);
21	  });
22	  it("should scale a single pixel image both horizontally and vertically", () => {
23	    expect(scalePixelArt([["x"]], 3)).toEqual([
24	      ["x", "x", "x"],
25	      ["x", "x", "x"],
26	      ["x", "x", "x"],
27	    ]);
28	  });
29	  it("should scale a multi-pixel row by scale factor", () => {
30	    expect(scalePixelArt([["a", "b", "c"]], 2)).toEqual([
31	      ["a", "a", "b", "b", "c", "c"],
32	      ["a", "a", "b", "b", "c", "c"],
33	    ]);
34	  });
35	  it.todo("should scale a multi-row image by scale factor");
36	  it.todo("should preserve character values exactly without blending");
37	});
