1	const repeat = <T>(value: T, times: number): T[] => Array(times).fill(value);
2	
3	export const scalePixelArt = (image: string[][], scale: number): string[][] =>
4	  image.flatMap((row) => repeat(row.flatMap((pixel) => repeat(pixel, scale)), scale));
